import React from 'react'

const Logout = () => {

    const navigate = useNavigate();

    const logout = () => {
        signInWithPopup(auth, provider).then((result) => {
            localStorage.setItem("isAuth", false);
            setIsAuth(false);
            navigate("/")
        })
    }

  return (
    <div>
              <p>今すぐ参加しましょう。</p>
        <button onClick={logout}><GoogleIcon className='login__googleIcon'/>Googleでログインする</button>

    </div>
  )
}

export default Logout
